package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat format = csvFormat.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withValuesContainingCommaAndQuotes() {
        String result = csvFormat.format("a,b", "\"quote\"", "c");
        assertEquals("\"a,b\",\"\"\"quote\"\"\",c", result);
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Mock CSVPrinter and inject it via reflection into CSVFormat.format method invocation
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        // Disambiguate printRecord call to printRecord(Object...) by casting argument
        doThrow(new IOException("io error")).when(mockPrinter).printRecord((Object[]) any());

        // Use reflection to invoke the private method format(Object...) of CSVFormat
        // but replace the CSVPrinter creation with our mock using a proxy/wrapper

        // Create a subclass of CSVFormat with overridden format method that uses the mockPrinter
        CSVFormat format = new CSVFormatWrapper(csvFormat, mockPrinter);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            format.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("io error", thrown.getCause().getMessage());
    }

    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVPrinter mockPrinter;

        CSVFormatWrapper(CSVFormat base, CSVPrinter mockPrinter) {
            // Use base's withXxx methods to copy all settings since constructor is private
            super(); // dummy call, will not be used since CSVFormat is final, workaround below
            this.mockPrinter = mockPrinter;
            // Because CSVFormat is final and has no accessible constructor, use reflection to copy fields
            copyFields(base);
        }

        private void copyFields(CSVFormat base) {
            try {
                for (java.lang.reflect.Field field : CSVFormat.class.getDeclaredFields()) {
                    field.setAccessible(true);
                    field.set(this, field.get(base));
                }
            } catch (IllegalAccessException e) {
                throw new RuntimeException(e);
            }
        }

        @Override
        public String format(final Object... values) {
            final StringWriter out = new StringWriter();
            try {
                mockPrinter.printRecord(values);
                return out.toString().trim();
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }
    }

    @Test
    public void testFormat_privateMethodInvocation() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);
        formatMethod.setAccessible(true);
        String result = (String) formatMethod.invoke(csvFormat, (Object) new Object[]{"x", "y"});
        assertEquals("x,y", result);
    }

}
